// 2.7.2 - 2022-02-15 - raj -  DFCT0010800 - "Run Template" button is available on the "Template modal" when "Template" is INACTIVE ( cleared the bug, but also deactivated this)
*/
// Script Continued Below
(function executeRule(current, previous /*null when async*/) {
	var processTemplateTaskTableName = "x_153465_discovert_route_tasks";
	var tcs = new TaskerCommonScriptingMethods();
	try {
		// STRY0076016 - fixing permissions on members
		var UserPermissions  = new UserInfoScripts();
		var answer = false;
		answer = UserPermissions.userHasProcessRights(current);

		if(!answer) {
			tcs.commonMessage("Template Task", "You are not permitted to perform this operation.", gs.addErrorMessage);
			current.active = previous.active;
			current.setWorkflow(false);
			current.update();
		} else {
			current.active = false;
			current.setWorkflow(false);
			current.update();
			var processTemplateTaskQuery = [];
			var markInactive = function(record) {
				record.active = false;
				record.update();
				return true;
			};
			processTemplateTaskQuery.push({"parent":current.sys_id});
			var numberOfSet = tcs.queryRelated(processTemplateTaskTableName, processTemplateTaskQuery, markInactive);
		}
	} catch(e) {
		tcs.checkException("Template Task", gs.warn, e);
	}
})(current, previous);
